SELECT 
  FROM ops_operational_exception
 WHERE tenant_id = #{tenantId}



            AND project_id IN

                CAST(#{scopedProjectId} AS uuid)



            AND 1 = 0



AND project_id = CAST(#{projectId} AS uuid)
AND status = #{status}
AND category_code = #{category}
AND severity_code = #{severity}
AND work_order_id = #{workOrderId}
AND task_id = #{taskId}

    AND (opened_at, exception_id) < (#{cursorOpenedAt}, #{cursorId})

 ORDER BY opened_at DESC, exception_id DESC
 LIMIT #{fetchSize}

SELECT 
  FROM ops_operational_exception
 WHERE tenant_id = #{tenantId} AND exception_id = #{exceptionId}

