UPDATE ops_operational_exception
   SET status = 'ACKNOWLEDGED', acknowledged_at = #{acknowledgedAt},
       acknowledged_by = #{actorId}, acknowledgement_note = #{note},
       aggregate_version = aggregate_version + 1
 WHERE tenant_id = #{tenantId} AND exception_id = #{exceptionId}
   AND status = 'OPEN' AND aggregate_version = #{expectedVersion}

